import{_ as i,o as t,c as a,ag as o}from"./chunks/framework.Cqf6AMW8.js";const M=JSON.parse('{"title":"JavaScript DOM基础","description":"JavaScript DOM基础相关知识，包括DOM的作用和分类、DOM树、DOM对象等。","frontmatter":{"title":"JavaScript DOM基础","description":"JavaScript DOM基础相关知识，包括DOM的作用和分类、DOM树、DOM对象等。","date":"2026-04-21T00:00:00.000Z","tags":["JavaScript","DOM","基础"],"sidebar":"auto"},"headers":[],"relativePath":"docs/frontend/javascript/JS-DOM-4-DOM基础.md","filePath":"docs/frontend/javascript/JS-DOM-4-DOM基础.md","lastUpdated":1776715536000}'),r={name:"docs/frontend/javascript/JS-DOM-4-DOM基础.md"};function e(n,l,s,p,u,d){return t(),a("div",null,[...l[0]||(l[0]=[o('<p>#JavaScript</p><p>======================================================</p><h2 id="_1-作用和分类" tabindex="-1">1. 作用和分类 <a class="header-anchor" href="#_1-作用和分类" aria-label="Permalink to &quot;1. 作用和分类&quot;">​</a></h2><ul><li><p><strong>作用</strong>：就是使用 JS 去操作 html 和浏览器</p></li><li><p><strong>分类</strong>：</p><ul><li>DOM (Document Object Model，文档对象模型)</li><li>BOM (Browser Object Model，浏览器对象模型)</li></ul></li><li><p><strong>JavaScript 的组成</strong>：</p><ul><li>ECMAScript：JavaScript 语言基础</li><li>Web APIs： <ul><li>DOM：页面文档对象模型</li><li>BOM：浏览器对象模型</li></ul></li></ul></li></ul><p>======================================================</p><h2 id="_2-什么是-dom" tabindex="-1">2. 什么是 DOM <a class="header-anchor" href="#_2-什么是-dom" aria-label="Permalink to &quot;2. 什么是 DOM&quot;">​</a></h2><ul><li><p><strong>DOM (Document Object Model)</strong>：是用来呈现以及与任意 HTML 或 XML 文档交互的 API</p></li><li><p><strong>白话文</strong>：DOM 是浏览器提供的一套专门用来操作网页内容的功能</p></li><li><p><strong>DOM 作用</strong>：</p><ul><li>开发网页内容特效</li><li>实现用户交互</li></ul></li></ul><p>======================================================</p><h2 id="_3-dom-树" tabindex="-1">3. DOM 树 <a class="header-anchor" href="#_3-dom-树" aria-label="Permalink to &quot;3. DOM 树&quot;">​</a></h2><ul><li><p><strong>DOM 树是什么</strong>：</p><ul><li>将 HTML 文档以树状结构直观的表现出来，我们称之为文档树或 DOM 树</li><li>描述网页内容关系的名词</li><li><strong>作用</strong>：文档树直观的体现了标签与标签之间的关系</li></ul></li><li><p><strong>DOM 树结构示例</strong>：</p><ul><li>Document <ul><li>html <ul><li>head <ul><li>meta</li><li>title</li><li>link</li></ul></li><li>body <ul><li>div</li><li>p</li><li>img</li><li>button</li></ul></li></ul></li></ul></li></ul></li></ul><p>======================================================</p><h2 id="_4-dom-对象" tabindex="-1">4. DOM 对象 <a class="header-anchor" href="#_4-dom-对象" aria-label="Permalink to &quot;4. DOM 对象&quot;">​</a></h2><ul><li><p><strong>DOM 对象</strong>：浏览器根据 html 标签生成的 JS 对象</p><ul><li>所有的标签属性都可以在这个对象上面找到</li><li>修改这个对象的属性会自动映射到标签身上</li></ul></li><li><p><strong>DOM 的核心思想</strong>：</p><ul><li>把网页内容当做对象来处理</li></ul></li><li><p><strong>document 对象</strong>：</p><ul><li>是 DOM 里提供的一个对象</li><li>所以它提供的属性和方法都是用来访问和操作网页内容的</li><li>例：document.write()</li><li>网页所有内容都在 document 里面</li></ul></li></ul><p>======================================================</p>',14)])])}const O=i(r,[["render",e]]);export{M as __pageData,O as default};
